-- Rebuild ACBANK Clear/Bright/Satin color masters from the 2026-05-21 color-code source.
-- Scope:
-- - Clear A/B replaces legacy glossy-color color rows, including removal of AC-C006/007/008.
-- - Bright A/B is stored under bright-color instead of the old satin-color placeholder.
-- - Satin is restored as its own satin-color color set.

INSERT INTO public.panel_masters (material, quality, name, description)
VALUES
  ('acrylic', 'glossy-color', 'Clear (클리어)', 'CLEAR A/B 유광 색상판'),
  ('acrylic', 'bright-color', 'Bright (브라이트)', 'BRIGHT A/B 흰색 안료 계열 색상판'),
  ('acrylic', 'satin-color', 'Satin (사틴)', 'SATIN 사틴 소재 색상판'),
  ('acrylic', 'satin-mirror', 'Satin Mirror (사틴 미러)', 'SATIN MIRROR 미러 계열 색상판')
ON CONFLICT (material, quality) DO UPDATE
SET name = EXCLUDED.name,
    description = EXCLUDED.description,
    updated_at = now();

CREATE TEMP TABLE acbank_color_seed (
  series_key TEXT NOT NULL,
  series_label TEXT NOT NULL,
  quality TEXT NOT NULL,
  color_name TEXT NOT NULL,
  color_code TEXT NOT NULL,
  pantone TEXT NOT NULL,
  source_url TEXT NOT NULL,
  display_order INTEGER NOT NULL,
  is_bright_pigment BOOLEAN NOT NULL
) ON COMMIT DROP;

