  ('BRIGHT_B', 'BRIGHT B', 'bright-color', 'AC-B177', '#F277C6', 'PT 231C', 'https://www.acbank.co.kr/BRIGHT_B/?idx=291', 134, true),
  ('BRIGHT_B', 'BRIGHT B', 'bright-color', 'AC-B178', '#E93CAC', 'PT 232C', 'https://www.acbank.co.kr/BRIGHT_B/?idx=292', 135, true),
  ('BRIGHT_B', 'BRIGHT B', 'bright-color', 'AC-B179', '#D0006F', 'PT 226C', 'https://www.acbank.co.kr/BRIGHT_B/?idx=293', 136, true);

DELETE FROM public.color_options co
USING public.panel_masters pm
WHERE co.panel_master_id = pm.id
  AND pm.material = 'acrylic'
  AND pm.quality IN ('glossy-color', 'bright-color', 'satin-color');

INSERT INTO public.color_options (
  panel_master_id,
  color_name,
  color_code,
  is_active,
  display_order,
  is_producible,
  is_bright_pigment,
  unavailable_reason,
  color_attribute_note,
  series_key,
  pantone,
  source_url
)
SELECT
  pm.id,
  seed.color_name,
  seed.color_code,
  true,
  seed.display_order,
  true,
  seed.is_bright_pigment,
  null,
  concat(seed.series_label, ' / ', seed.pantone),
  seed.series_key,
  seed.pantone,
  seed.source_url
FROM acbank_color_seed seed
JOIN public.panel_masters pm
  ON pm.material = 'acrylic'
 AND pm.quality::TEXT = seed.quality
ORDER BY seed.quality, seed.display_order;

-- Post-migration guardrail: legacy Clear B placeholder rows must not remain.
DO $$
BEGIN
  IF EXISTS (
    SELECT 1
    FROM public.color_options co
    JOIN public.panel_masters pm ON pm.id = co.panel_master_id
    WHERE pm.material = 'acrylic'
      AND pm.quality = 'glossy-color'
      AND co.color_name IN ('AC-C006', 'AC-C007', 'AC-C008')
  ) THEN
    RAISE EXCEPTION 'Legacy CLEAR B colors AC-C006/007/008 still exist after rebuild';
  END IF;
END $$;
